#!/bin/bash
# Skill eval verifier — runs LLM judge against agent trajectory.
# Generated by benchflow skill-eval. Do not edit.
set -e

VERIFIER_DIR="${BENCHFLOW_VERIFIER_DIR:-/verifier}"
if [ ! -f "$VERIFIER_DIR/judge.py" ]; then
    VERIFIER_DIR=/tests
fi
REWARD_TEXT="${BENCHFLOW_REWARD_TEXT:-/logs/verifier/reward.txt}"
REWARD_JSON="${BENCHFLOW_REWARD_JSON:-/logs/verifier/reward.json}"
JUDGE_RESULT_JSON="${BENCHFLOW_REWARD_DETAILS_JSON:-/logs/verifier/judge_result.json}"

mkdir -p "$(dirname "$REWARD_TEXT")" "$(dirname "$REWARD_JSON")" "$(dirname "$JUDGE_RESULT_JSON")"
cd "$VERIFIER_DIR"

python3 "$VERIFIER_DIR/judge.py"

cp "$VERIFIER_DIR/reward.txt" "$REWARD_TEXT"
if [ -f "$VERIFIER_DIR/reward.json" ]; then
    cp "$VERIFIER_DIR/reward.json" "$REWARD_JSON"
fi

# Copy criterion-level rubric details where the skill-eval collector reads
# them (#406). judge.py writes judge_result.json beside itself; without this
# copy CaseResult.rubric_results was silently None even when the judge
# produced rich detail.
if [ -f "$VERIFIER_DIR/judge_result.json" ]; then
    cp "$VERIFIER_DIR/judge_result.json" "$JUDGE_RESULT_JSON"
fi
